export function FullStackIcon({className}: {className?: string}) {
  return (
    <svg viewBox="0 0 24 24" fill="none" className={className}>
      {/* top layer */}
      <rect x="4" y="4" width="16" height="3" rx="1" fill="currentColor" />

      {/* middle layer */}
      <rect x="4" y="10" width="16" height="3" rx="1" fill="currentColor" />

      {/* bottom layer */}
      <rect x="4" y="16" width="16" height="3" rx="1" fill="currentColor" />

      {/* connection line */}
      <path
        d="M12 7v3M12 13v3"
        stroke="currentColor"
        strokeWidth="2"
        strokeLinecap="round"
      />
    </svg>
  );
}
